using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Instantiate tools ---
var notepad = new Notepad();

IList<AITool> tools =
[
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
];

// --- Create the research agent ---
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. Given a topic, you perform web searches to gather 
        information, take notes on key findings, then produce a concise summary.

        Follow this workflow:
        1. Search the web for the topic using multiple relevant queries.
        2. Take notes on the most important facts and findings.
        3. Review your notes and produce a well-structured summary.

        Always cite sources when possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session: null,
    options: runOptions);

// --- Display results ---
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════");

if (notepad.Notes.Count > 0)
{
    Console.WriteLine($"\n📝 Notes taken during research ({notepad.Notes.Count}):");
    for (int i = 0; i < notepad.Notes.Count; i++)
    {
        Console.WriteLine($"  {i + 1}. {notepad.Notes[i]}");
    }
}

// ═══════════════════════════════════════════
// Tool Definitions
// ═══════════════════════════════════════════

/// <summary>
/// Provides web search capability for the research agent.
/// </summary>
static class WebSearch
{
    [Description("Searches the web for information on a given query and returns relevant results.")]
    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        // Simulate network latency
        await Task.Delay(100);

        // In production, replace with a real search API (e.g., Bing Search, Google Custom Search).
        // This simulated implementation returns plausible results for demonstration purposes.
        return $"""
            Search results for: "{query}"

            1. [Wikipedia] Overview article covering key aspects of {query}.
               URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}
               Snippet: {query} is a topic of significant interest with multiple dimensions
               including historical context, current developments, and future implications.

            2. [Research Paper] "A Comprehensive Analysis of {query}" - Journal of Technology, 2024.
               URL: https://doi.org/10.1234/example
               Snippet: This paper provides an in-depth examination of {query}, covering methodology,
               key findings, and practical applications.

            3. [News] Latest developments in {query} - TechNews, May 2026.
               URL: https://technews.example.com/{Uri.EscapeDataString(query)}
               Snippet: Recent breakthroughs and trends in {query} suggest continued growth
               and innovation in this space.
            """;
    }
}

/// <summary>
/// Provides note-taking capability for the research agent.
/// </summary>
sealed class Notepad
{
    public List<string> Notes { get; } = [];

    [Description("Adds a note to the research notepad for later reference when writing the summary.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        Notes.Add(note);
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Retrieves all notes taken so far during the research session.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        return string.Join("\n", Notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

