         3. Review your notes and produce a well-structured summary.

         Always cite sources when possible.
         """,
     name: "ResearchAgent",
     description: "Researches topics by searching the web and summarizing findings",
     tools: tools);

 // --- Get the research topic ---
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Run the agent ---
 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 2048,
 });

 var response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session: null,
     options: runOptions);

 // --- Display results ---
 Console.WriteLine("═══════════════════════════════════════════");
 Console.WriteLine("📋 RESEARCH SUMMARY");
 Console.WriteLine("═══════════════════════════════════════════");
 Console.WriteLine(response.Text);
 Console.WriteLine("═══════════════════════════════════════════");

 if (notepad.Notes.Count > 0)
 {
     Console.WriteLine($"\n📝 Notes taken during research ({notepad.Notes.Count}):");
     for (int i = 0; i < notepad.Notes.Count; i++)
     {
         Console.WriteLine($"  {i + 1}. {notepad.Notes[i]}");
     }
 }

